(5,	1,	'2026-03-30 10:45:42',	'2026-03-30 10:45:42',	'<a href=\"#\">\n									Information Technology Student\n					</a>\n									<h2>Hello, I’m Rowena\nMasugod</h2>		<p>Passionate about creating innovative solutions and beautiful user experiences</p>								<a href=\"#\">\n									Download Resume\n					</a>\n														<a href=\"#\">\n									Get In Touch\n					</a>\n																			<img width=\"500\" height=\"500\" src=\"http://portfoliomasugod.local/wp-content/uploads/2026/04/d4e398870d8f93dc54b01c488538c737-removebg-preview.png\" alt=\"\" srcset=\"http://portfoliomasugod.local/wp-content/uploads/2026/04/d4e398870d8f93dc54b01c488538c737-removebg-preview.png 500w, http://portfoliomasugod.local/wp-content/uploads/2026/04/d4e398870d8f93dc54b01c488538c737-removebg-preview-300x300.png 300w, http://portfoliomasugod.local/wp-content/uploads/2026/04/d4e398870d8f93dc54b01c488538c737-removebg-preview-150x150.png 150w\" sizes=\"(max-width: 500px) 100vw, 500px\" />																<h2>About Me</h2>		<p>I\'m an Information Technology student with a passion for creating innovative digital solutions. My journey in tech has been driven by curiosity and a desire to solve real-world problems through code. INSERT INTO `wp_term_relationships` (`object_id`, `term_taxonomy_id`, `term_order`) VALUES
